output = []
for category, tools in new_tools.items():
    seen = set()
    for t in tools:
        if t["id"] in seen:
            continue
        seen.add(t["id"])
        pricing = f', pricing: "{t.get("pricing","Free")}"' if t.get("pricing") else ""
        verified = "true" if t.get("verified") else "false"
        line = f'      {{ id: "{t["id"]}", name: "{t["name"]}", description: "{t["description"]}", url: "{t["url"]}", upvotes: {t["upvotes"]}, verified: {verified}, rating: {t["rating"]}, icon: "{t["icon"]}", category: "{category}"{pricing} }},'
        output.append(line)

with open("new_tools_formatted.ts", "w") as f:
    f.write("\n".join(output))

total = sum(len(set(t["id"] for t in v)) for v in new_tools.values())
print(f"✅ Generated {total} new tools saved to new_tools_formatted.ts")
